tool_calls.call:
cat > /tmp/test_flip.c << 'EOF'
#include <stdio.h>

int main() {
    int a = 11;
    printf("~11 = %d\n", ~a);
    printf("-11 = %d\n", -a);
    return 0;
}
EOF
gcc /tmp/test_flip.c -o /tmp/test_flip && /tmp/test_flip

cat > /tmp/verify_fix.c << 'EOF'
#include <stdio.h>

int main() {
    int test_values[] = {0, 1, 11, -1, -12, 255, -256};
    int num_tests = sizeof(test_values) / sizeof(test_values[0]);

    for (int i = 0; i < num_tests; i++) {
        int val = test_values[i];
        printf("~%d = %d (correct), -%d = %d (wrong)\n", 
               val, ~val, val, -val);
    }

    return 0;
}
EOF
gcc /tmp/verify_fix.c -o /tmp/verify_fix && /tmp/verify_fix
